import datetimefrom libs.database.model import Modelfrom libs.database.types import Date, Number, Char, Date, Varchar2class BlacklistLists(Model):    __tablename__ = 'blacklist_lists'    id = Number(field='id')    date_created = Date(field='date_created',default=datetime.datetime.now())    date_modified = Date(field='date_modified')    user_id = Number(field='user_id')    account_id = Number(field='account_id')    name = Varchar2(field='name')    description = Varchar2(field='description')